package cli

import (
	"fmt"
	"os"
	"path/filepath"

	"github.com/jdbencardinop/tesseraworkspaces/internal"
)

func Add(args []string) {
	if len(args) < 1 {
		println("Usage: tws add <feature>")
		return
	}

	feature := args[0]
	root := internal.FeaturePath(feature)

	// Ensure .tws-workspace marker exists in workspace root
	wsRoot := internal.TwsRoot()
	internal.Must(os.MkdirAll(filepath.Join(wsRoot, ".tws-workspace"), 0755))

	// TODO: make worktress a constant in internal package
	internal.Must(os.MkdirAll(filepath.Join(root, "worktrees"), 0755))

	// TODO: either add a slug arg or pass the entire feature description and slugify it here
	internal.Must(os.WriteFile(filepath.Join(root, "FEATURE.md"), []byte("# "+feature+"\n"), 0644))

	// TODO: Add a template for other files, here we just create a CLAUDE.local.md file
	internal.Must(os.WriteFile(filepath.Join(root, "CLAUDE.local.md"), []byte("# "+feature+" - CLAUDE shared context\n"), 0644))

	fmt.Println("Feature added:", feature)
}

package cli

import (
	"fmt"
	"os"

	"github.com/jdbencardinop/tesseraworkspaces/internal"
)

func New(args []string) {
	if len(args) < 2 {
		println("Usage: tws new <feature> <branch> [--base <parent>]")
		return
	}

	internal.RequireTool("git")

	feature := args[0]
	branch := args[1]
	base := "main"

	// Parse --base flag
	for i := 2; i < len(args); i++ {
		if args[i] == "--base" && i+1 < len(args) {
			base = args[i+1]
			break
		}
	}

	featurePath := internal.FeaturePath(feature)
	path := internal.WorktreePath(feature, branch)

	// Ensure parent directory exists
	internal.Must(os.MkdirAll(featurePath, 0755))

	// Create the worktree at the feature-scoped path
	repoRoot, err := internal.MainRepoRoot()
	if err != nil {
		fmt.Println("Error: must be run from inside a git repository")
		os.Exit(1)
	}

	internal.Must(internal.RunDir(repoRoot, "git", "worktree", "add", path, "-b", branch))

	// Register branch in stack.yaml
	stack, _ := internal.LoadStack(featurePath)
	stack.Branches = append(stack.Branches, internal.StackEntry{Name: branch, Base: base})
	internal.Must(internal.SaveStack(featurePath, stack))

	fmt.Printf("Worktree created: %s (base: %s)\n", path, base)
}

package cli

import "github.com/jdbencardinop/tesseraworkspaces/internal"

func Open(args []string) {
	if len(args) < 2 {
		println("Usage: tws open <feature> <branch>")
		return
	}

	internal.RequireTool("tmux")

	feature := args[0]
	branch := args[1]

	path := internal.WorktreePath(feature, branch)
	session := feature + "__" + branch

	// TODO: we should validate if tmux is installed and available in PATH
	// we should consider making this an interface and allowing users to choose between different terminal multiplexers
	// we could probably do one of our own that is more lightweight and doesn't require tmux, but for now we can just use tmux or tmuxinator

	// Create tmux session if it doesn't exist
	internal.Run("tmux", "has-session", "-t", session)
	// if not exist, create it
	internal.Run("tmux", "new-session", "-d", "-s", session, "-c", path)

	// Configure tmux session with some default panes and commands
	// TODO: we should probably move this to a template file and copy it over instead of creating it from scratch

	// TODO: this pane should only be shown for the first time, we can probably check if the user has already opened this session before and skip this part if they have, we can store this information in a file in the feature directory or in a global config file
	internal.Run("tmux", "send-keys", "-t", session, "clear", "Enter")
	internal.Run("tmux", "send-keys", "-t", session, "echo 'Welcome to your Tesseraspaces session!'", "Enter")
	internal.Run("tmux", "send-keys", "-t", session, "echo 'Feature: "+feature+"'", "Enter")
	internal.Run("tmux", "send-keys", "-t", session, "echo 'Branch: "+branch+"'", "Enter")
	internal.Run("tmux", "send-keys", "-t", session, "echo 'Use tmux commands to manage your panes and windows.'", "Enter")

	// Start the normal session in the first window

	// Start a new window to put the rest of the stuff in
	internal.Run("tmux", "new-window", "-t", session, "-n", "claude", "-c", path)
	// Start claude
	// TODO: we should probably check if the user has claude installed and available in PATH
	// TODO: we could probably think about adding more providers like codex, copilot-cli or opencode
	internal.Run("tmux", "send-keys", "-t", session, ":1", "claude -c", "C-m")

	// TODO: we should probably check if the session is already attached to avoid attaching to it multiple times and causing issues
	internal.Must(internal.Run("tmux", "attach", "-t", session))
}

package cli

import (
	"fmt"
	"os"

	"github.com/jdbencardinop/tesseraworkspaces/internal"
)

func StackCmd(args []string) {
	if len(args) < 1 {
		println("Usage: tws stack <feature>")
		return
	}

	feature := args[0]
	featurePath := internal.FeaturePath(feature)

	stack, err := internal.LoadStack(featurePath)
	if err != nil {
		fmt.Println("No stack.yaml found for feature:", feature)
		os.Exit(1)
	}

	if _, err := internal.TopoSort(stack); err != nil {
		fmt.Printf("Warning: %v\n", err)
	}

	internal.PrintTree(stack)
}

package cli

import (
	"fmt"
	"os"
	"path/filepath"

	"github.com/jdbencardinop/tesseraworkspaces/internal"
)

func Sync(args []string) {
	if len(args) < 1 {
		println("Usage: tws sync <feature>")
		return
	}

	internal.RequireTool("git")

	feature := args[0]
	featurePath := internal.FeaturePath(feature)

	internal.Must(internal.Run("git", "fetch"))

	stack, err := internal.LoadStack(featurePath)
	if err != nil {
		// No stack.yaml — fall back to rebasing all worktrees against origin/main
		syncFallback(featurePath)
		return
	}

	sorted, err := internal.TopoSort(stack)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}

	skipped := make(map[string]bool)

	for _, entry := range sorted {
		if skipped[entry.Name] {
			fmt.Println(internal.FormatBranchStatus(entry.Name, "skipped"))
			continue
		}

		path := internal.WorktreePath(feature, entry.Name)
		if _, err := os.Stat(path); os.IsNotExist(err) {
			fmt.Println(internal.FormatBranchStatus(entry.Name, "skipped"))
			continue
		}

		base := entry.Base
		if base == "main" {
			base = "origin/main"
		}

		err := internal.RunDir(path, "git", "rebase", base)
		if err != nil {
			fmt.Println(internal.FormatBranchStatus(entry.Name, "failed"))
			// Skip all descendants
			descs := internal.Descendants(stack, entry.Name)
			for d := range descs {
				skipped[d] = true
			}
			fmt.Printf("    Skipping descendants: %s\n", internal.DescendantsList(stack, entry.Name))
		} else {
			fmt.Println(internal.FormatBranchStatus(entry.Name, "synced"))
		}
	}
}

func syncFallback(featurePath string) {
	entries, _ := os.ReadDir(filepath.Join(featurePath, "worktrees"))
	for _, e := range entries {
		if !e.IsDir() {
			continue
		}
		path := filepath.Join(featurePath, "worktrees", e.Name())
		fmt.Printf("Syncing worktree: %s\n", path)
		internal.Must(internal.RunDir(path, "git", "rebase", "--update-refs", "origin/main"))
	}
}

package internal

import (
	"os"
	"path/filepath"

	"gopkg.in/yaml.v3"
)

type Config struct {
	Workspaces map[string]string `yaml:"workspaces"`
}

func ConfigPath() string {
	home, _ := os.UserHomeDir()
	return filepath.Join(home, ".config", "tws", "config.yaml")
}

func LoadConfig() Config {
	data, err := os.ReadFile(ConfigPath())
	if err != nil {
		return Config{}
	}
	var cfg Config
	if err := yaml.Unmarshal(data, &cfg); err != nil {
		return Config{}
	}
	return cfg
}

package internal

import (
	"os"
	"path/filepath"
	"strings"
)

const workspaceMarker = ".tws-workspace"

// DetectWorkspaceRoot checks if cwd is inside an existing workspace.
// Returns the workspace root or empty string.
func DetectWorkspaceRoot(cwd string, cfg Config) string {
	// Tier 1: Walk up looking for .tws-workspace marker
	dir := cwd
	for {
		if _, err := os.Stat(filepath.Join(dir, workspaceMarker)); err == nil {
			return dir
		}
		parent := filepath.Dir(dir)
		if parent == dir {
			break
		}
		dir = parent
	}

	// Tier 2: Check if cwd is inside any configured workspace path
	for _, ws := range cfg.Workspaces {
		absWs, err := filepath.Abs(ws)
		if err != nil {
			continue
		}
		absCwd, err := filepath.Abs(cwd)
		if err != nil {
			continue
		}
		if strings.HasPrefix(absCwd, absWs+string(filepath.Separator)) || absCwd == absWs {
			return absWs
		}
	}

	// Tier 3: Check if cwd is inside ~/tws
	home, _ := os.UserHomeDir()
	globalDefault := filepath.Join(home, "tws")
	absCwd, _ := filepath.Abs(cwd)
	if strings.HasPrefix(absCwd, globalDefault+string(filepath.Separator)) || absCwd == globalDefault {
		return globalDefault
	}

	return ""
}

// resolveTwsRoot contains the resolution logic with injectable dependencies.
func resolveTwsRoot(envRoot string, cwd string, repoRoot string, repoErr error, cfg Config) string {
	// 0. TWS_ROOT env var — always wins
	if envRoot != "" {
		return envRoot
	}

	// 1. Already inside a workspace? Return that root.
	if wsRoot := DetectWorkspaceRoot(cwd, cfg); wsRoot != "" {
		return wsRoot
	}

	// 2. Global config keyed by repo path
	if repoErr == nil {
		if ws, ok := cfg.Workspaces[repoRoot]; ok {
			return ws
		}

		// 3. Repo-relative sibling: ../<repo-name>.tws/
		repoName := filepath.Base(repoRoot)
		return filepath.Join(filepath.Dir(repoRoot), repoName+".tws")
	}

	// 4. Global fallback
	home, _ := os.UserHomeDir()
	return filepath.Join(home, "tws")
}

func TwsRoot() string {
	repoRoot, repoErr := MainRepoRoot()
	cfg := LoadConfig()
	cwd, _ := os.Getwd()
	return resolveTwsRoot(os.Getenv("TWS_ROOT"), cwd, repoRoot, repoErr, cfg)
}

func FeaturePath(feature string) string {
	return filepath.Join(TwsRoot(), feature)
}

func WorktreePath(feature, branch string) string {
	return filepath.Join(FeaturePath(feature), "worktrees", branch)
}

package internal

import (
	"errors"
	"os"
	"path/filepath"
	"testing"
)

func TestResolveTwsRoot_EnvVar(t *testing.T) {
	got := resolveTwsRoot("/custom/root", "/somewhere", "/some/repo", nil, Config{})
	if got != "/custom/root" {
		t.Errorf("expected /custom/root, got %s", got)
	}
}

func TestResolveTwsRoot_ConfigEntry(t *testing.T) {
	cfg := Config{Workspaces: map[string]string{
		"/Users/me/projects/myapp": "/data/workspaces/myapp",
	}}
	got := resolveTwsRoot("", "/somewhere", "/Users/me/projects/myapp", nil, cfg)
	if got != "/data/workspaces/myapp" {
		t.Errorf("expected /data/workspaces/myapp, got %s", got)
	}
}

func TestResolveTwsRoot_RepoSibling(t *testing.T) {
	got := resolveTwsRoot("", "/somewhere", "/Users/me/projects/myapp", nil, Config{})
	want := "/Users/me/projects/myapp.tws"
	if got != want {
		t.Errorf("expected %s, got %s", want, got)
	}
}

func TestResolveTwsRoot_Fallback(t *testing.T) {
	got := resolveTwsRoot("", "/somewhere", "", errors.New("not a repo"), Config{})
	home, _ := os.UserHomeDir()
	want := filepath.Join(home, "tws")
	if got != want {
		t.Errorf("expected %s, got %s", want, got)
	}
}

func TestResolveTwsRoot_EnvWinsOverConfig(t *testing.T) {
	cfg := Config{Workspaces: map[string]string{
		"/some/repo": "/configured/path",
	}}
	got := resolveTwsRoot("/env/override", "/somewhere", "/some/repo", nil, cfg)
	if got != "/env/override" {
		t.Errorf("env should win, got %s", got)
	}
}

func TestResolveTwsRoot_ConfigWinsOverSibling(t *testing.T) {
	cfg := Config{Workspaces: map[string]string{
		"/Users/me/projects/myapp": "/explicit/path",
	}}
	got := resolveTwsRoot("", "/somewhere", "/Users/me/projects/myapp", nil, cfg)
	if got != "/explicit/path" {
		t.Errorf("config should win over sibling, got %s", got)
	}
}

func TestFeaturePath(t *testing.T) {
	root := resolveTwsRoot("/ws", "/somewhere", "", errors.New("no repo"), Config{})
	want := "/ws/auth"
	got := filepath.Join(root, "auth")
	if got != want {
		t.Errorf("expected %s, got %s", want, got)
	}
}

func TestWorktreePath(t *testing.T) {
	root := resolveTwsRoot("/ws", "/somewhere", "", errors.New("no repo"), Config{})
	want := "/ws/auth/worktrees/login-fix"
	got := filepath.Join(root, "auth", "worktrees", "login-fix")
	if got != want {
		t.Errorf("expected %s, got %s", want, got)
	}
}

// --- Workspace detection tests ---

func TestDetectWorkspaceRoot_MarkerFile(t *testing.T) {
	tmp := t.TempDir()
	wsRoot := filepath.Join(tmp, "myapp.tws")
	nested := filepath.Join(wsRoot, "auth", "worktrees", "branch-a")
	os.MkdirAll(filepath.Join(wsRoot, ".tws-workspace"), 0755)
	os.MkdirAll(nested, 0755)

	got := DetectWorkspaceRoot(nested, Config{})
	if got != wsRoot {
		t.Errorf("expected %s, got %s", wsRoot, got)
	}
}

func TestDetectWorkspaceRoot_ConfigMatch(t *testing.T) {
	tmp := t.TempDir()
	wsRoot := filepath.Join(tmp, "custom-workspace")
	nested := filepath.Join(wsRoot, "feature", "worktrees", "branch")
	os.MkdirAll(nested, 0755)

	cfg := Config{Workspaces: map[string]string{
		"/some/repo": wsRoot,
	}}
	got := DetectWorkspaceRoot(nested, cfg)
	if got != wsRoot {
		t.Errorf("expected %s, got %s", wsRoot, got)
	}
}

func TestDetectWorkspaceRoot_GlobalDefault(t *testing.T) {
	home, _ := os.UserHomeDir()
	globalDefault := filepath.Join(home, "tws")

	nested := filepath.Join(globalDefault, "some-feature")
	if _, err := os.Stat(globalDefault); os.IsNotExist(err) {
		os.MkdirAll(nested, 0755)
		defer os.RemoveAll(globalDefault)
	} else {
		os.MkdirAll(nested, 0755)
		defer os.Remove(nested)
	}

	got := DetectWorkspaceRoot(nested, Config{})
	if got != globalDefault {
		t.Errorf("expected %s, got %s", globalDefault, got)
	}
}

func TestDetectWorkspaceRoot_NoMatch(t *testing.T) {
	got := DetectWorkspaceRoot("/some/random/path", Config{})
	if got != "" {
		t.Errorf("expected empty string, got %s", got)
	}
}

func TestResolveTwsRoot_WorkspaceDetectionWins(t *testing.T) {
	tmp := t.TempDir()
	wsRoot := filepath.Join(tmp, "myapp.tws")
	cwd := filepath.Join(wsRoot, "auth", "worktrees", "branch-a")
	os.MkdirAll(filepath.Join(wsRoot, ".tws-workspace"), 0755)
	os.MkdirAll(cwd, 0755)

	got := resolveTwsRoot("", cwd, "/some/repo", nil, Config{})
	if got != wsRoot {
		t.Errorf("workspace detection should win, expected %s, got %s", wsRoot, got)
	}
}
